    "round_step": 5,
    "due_date": "2064-09-14",
    "issue_date": "2026-05-10T23:47:59",
    "reference_number": "quia",
    "warehouse_id": 19,
    "cash_box_id": 19,
    "user_cash_box_id": 8,
    "user_id": 2,
    "notes": "et",
    "items": [
        {
            "attributes": [
                {
                    "id": 13,
                    "attribute_id": 9,
                    "attribute_value_id": 15
                }
            ],
            "stocks": [
                {
                    "id": 7,
                    "quantity": 1,
                    "reserved": 19,
                    "min_quantity": 15,
                    "cost": 1.76165974,
                    "batch": "enim",
                    "expiry": "2026-05-10T23:47:59",
                    "loc": "maiores",
                    "status": "dignissimos"
                }
            ]
        }
    ],
    "installment_plan": {
        "down_payment": 20986242,
        "number_of_installments": 53,
        "installment_amount": 614.64341,
        "total_amount": 679.57,
        "start_date": "2026-05-10T23:47:59",
        "due_date": "2026-05-10T23:47:59",
        "round_step": 6,
        "net_amount": 3544988,
        "interest_rate": 1.707,
        "interest_amount": 15963088.04291084,
        "frequency": "quarterly"
    }
};

fetch(url, {
    method: "POST",
    headers,
    body: JSON.stringify(body),
}).then(response =&gt; response.json());</code></pre></div>

