                    <h2 id="03-adar-almntgat-oalmkhzon-GETapi-v1-stocks">عرض قائمة حركات المخزون

تتبع حركة المخزن الواردة والصادرة (رصيد افتتاحي، مبيعات، مشتريات، تسويات).</h2>

<p>
<small class="badge badge-darkred">requires authentication</small>
</p>



<span id="example-requests-GETapi-v1-stocks">
<blockquote>Example request:</blockquote>


<div class="bash-example">
    <pre><code class="language-bash">curl --request GET \
    --get "http://localhost/api/v1/stocks?variant_id=1&amp;warehouse_id=1&amp;status=in&amp;quantity_from=10&amp;quantity_to=100&amp;created_at_from=2023-01-01&amp;created_at_to=2023-12-31&amp;sort_by=created_at&amp;sort_order=asc&amp;per_page=50" \
    --header "Authorization: Bearer {YOUR_AUTH_KEY}" \
    --header "Content-Type: application/json" \
    --header "Accept: application/json"</code></pre></div>


<div class="javascript-example">
    <pre><code class="language-javascript">const url = new URL(
    "http://localhost/api/v1/stocks"
);

const params = {
    "variant_id": "1",
    "warehouse_id": "1",
    "status": "in",
    "quantity_from": "10",
    "quantity_to": "100",
    "created_at_from": "2023-01-01",
    "created_at_to": "2023-12-31",
    "sort_by": "created_at",
    "sort_order": "asc",
    "per_page": "50",
};
Object.keys(params)
    .forEach(key =&gt; url.searchParams.append(key, params[key]));

const headers = {
    "Authorization": "Bearer {YOUR_AUTH_KEY}",
    "Content-Type": "application/json",
    "Accept": "application/json",
};


fetch(url, {
    method: "GET",
    headers,
}).then(response =&gt; response.json());</code></pre></div>

