<blockquote>Example request:</blockquote>


<div class="bash-example">
    <pre><code class="language-bash">curl --request POST \
    "http://localhost/api/v1/products" \
    --header "Authorization: Bearer {YOUR_AUTH_KEY}" \
    --header "Content-Type: application/json" \
    --header "Accept: application/json" \
    --data "{
    \"name\": \"آيفون 15 بروميجا\",
    \"product_type\": \"service\",
    \"require_stock\": false,
    \"is_downloadable\": false,
    \"download_url\": \"http:\\/\\/ritchie.com\\/ratione-doloribus-et-voluptas-enim-porro-ipsum-dolor-et\",
    \"download_limit\": 87,
    \"validity_days\": 3,
    \"expires_at\": \"2026-05-10T23:47:59\",
    \"delivery_instructions\": \"deserunt\",
    \"image_ids\": [
        15
    ],
    \"primary_image_id\": 10,
    \"published_at\": \"2026-05-10T23:47:59\",
    \"desc\": \"porro\",
    \"desc_long\": \"eligendi\",
    \"category_id\": 3,
    \"active\": true,
    \"featured\": true,
    \"returnable\": false,
    \"variants\": [
        {
            \"stocks\": [
                {
                    \"id\": 11,
                    \"quantity\": 72
                }
            ]
        }
    ]
}"
</code></pre></div>


<div class="javascript-example">
    <pre><code class="language-javascript">const url = new URL(
    "http://localhost/api/v1/products"
);

const headers = {
    "Authorization": "Bearer {YOUR_AUTH_KEY}",
    "Content-Type": "application/json",
    "Accept": "application/json",
};

let body = {
    "name": "آيفون 15 بروميجا",
    "product_type": "service",
    "require_stock": false,
    "is_downloadable": false,
    "download_url": "http:\/\/ritchie.com\/ratione-doloribus-et-voluptas-enim-porro-ipsum-dolor-et",
    "download_limit": 87,
    "validity_days": 3,
    "expires_at": "2026-05-10T23:47:59",
    "delivery_instructions": "deserunt",
    "image_ids": [
