    "desc": "porro",
    "desc_long": "eligendi",
    "category_id": 3,
    "active": true,
    "featured": true,
    "returnable": false,
    "variants": [
        {
            "stocks": [
                {
                    "id": 11,
                    "quantity": 72
                }
            ]
        }
    ]
};

fetch(url, {
    method: "POST",
    headers,
    body: JSON.stringify(body),
}).then(response =&gt; response.json());</code></pre></div>

