                                <h2 id="06-alaamlyat-almaly-oalkhzyn-POSTapi-v1-transactions-transfer">تحويل الرصيد (Transfer)

إجراء عملية تحويل رصيد من صندوق مستخدم إلى صندوق مستخدم آخر أو لنفس المستخدم في صندوق آخر.</h2>

<p>
<small class="badge badge-darkred">requires authentication</small>
</p>



<span id="example-requests-POSTapi-v1-transactions-transfer">
<blockquote>Example request:</blockquote>


<div class="bash-example">
    <pre><code class="language-bash">curl --request POST \
    "http://localhost/api/v1/transactions/transfer" \
    --header "Authorization: Bearer {YOUR_AUTH_KEY}" \
    --header "Content-Type: application/json" \
    --header "Accept: application/json" \
    --data "{
    \"target_user_id\": 2,
    \"amount\": 100,
    \"from_cash_box_id\": 1,
    \"to_cash_box_id\": 2,
    \"description\": \"تحويل داخلي\"
}"
</code></pre></div>


<div class="javascript-example">
    <pre><code class="language-javascript">const url = new URL(
    "http://localhost/api/v1/transactions/transfer"
);

const headers = {
    "Authorization": "Bearer {YOUR_AUTH_KEY}",
    "Content-Type": "application/json",
    "Accept": "application/json",
};

let body = {
    "target_user_id": 2,
    "amount": 100,
    "from_cash_box_id": 1,
    "to_cash_box_id": 2,
    "description": "تحويل داخلي"
};

fetch(url, {
    method: "POST",
    headers,
    body: JSON.stringify(body),
}).then(response =&gt; response.json());</code></pre></div>

