                    <h2 id="06-alaamlyat-almaly-oalkhzyn-GETapi-v1-cash-boxes">عرض قائمة الخزن</h2>

<p>
<small class="badge badge-darkred">requires authentication</small>
</p>



<span id="example-requests-GETapi-v1-cash-boxes">
<blockquote>Example request:</blockquote>


<div class="bash-example">
    <pre><code class="language-bash">curl --request GET \
    --get "http://localhost/api/v1/cash-boxes?current_user=1&amp;name=%D8%A7%D9%84%D8%AE%D8%B2%D9%86%D8%A9+%D8%A7%D9%84%D8%B1%D8%A6%D9%8A%D8%B3%D9%8A%D8%A9&amp;account_number=123456&amp;created_at_from=2023-01-01&amp;user_id=2&amp;per_page=20" \
    --header "Authorization: Bearer {YOUR_AUTH_KEY}" \
    --header "Content-Type: application/json" \
    --header "Accept: application/json"</code></pre></div>


<div class="javascript-example">
    <pre><code class="language-javascript">const url = new URL(
    "http://localhost/api/v1/cash-boxes"
);

const params = {
    "current_user": "1",
    "name": "الخزنة الرئيسية",
    "account_number": "123456",
    "created_at_from": "2023-01-01",
    "user_id": "2",
    "per_page": "20",
};
Object.keys(params)
    .forEach(key =&gt; url.searchParams.append(key, params[key]));

const headers = {
    "Authorization": "Bearer {YOUR_AUTH_KEY}",
    "Content-Type": "application/json",
    "Accept": "application/json",
};


fetch(url, {
    method: "GET",
    headers,
