                    <h2 id="06-alaamlyat-almaly-oalkhzyn-GETapi-v1-payments">عرض قائمة المدفوعات</h2>

<p>
<small class="badge badge-darkred">requires authentication</small>
</p>



<span id="example-requests-GETapi-v1-payments">
<blockquote>Example request:</blockquote>


<div class="bash-example">
    <pre><code class="language-bash">curl --request GET \
    --get "http://localhost/api/v1/payments?user_id=1&amp;payment_method_id=1&amp;cash_box_id=1&amp;amount_from=100&amp;amount_to=1000&amp;paid_at_from=2023-01-01&amp;per_page=7" \
    --header "Authorization: Bearer {YOUR_AUTH_KEY}" \
    --header "Content-Type: application/json" \
    --header "Accept: application/json"</code></pre></div>


<div class="javascript-example">
    <pre><code class="language-javascript">const url = new URL(
    "http://localhost/api/v1/payments"
);

const params = {
    "user_id": "1",
    "payment_method_id": "1",
    "cash_box_id": "1",
    "amount_from": "100",
    "amount_to": "1000",
    "paid_at_from": "2023-01-01",
    "per_page": "7",
};
Object.keys(params)
    .forEach(key =&gt; url.searchParams.append(key, params[key]));

const headers = {
    "Authorization": "Bearer {YOUR_AUTH_KEY}",
    "Content-Type": "application/json",
    "Accept": "application/json",
};


fetch(url, {
    method: "GET",
    headers,
}).then(response =&gt; response.json());</code></pre></div>

