    \"use_credit\": false,
    \"paid_at\": \"2023-05-20 14:30:00\"
}"
</code></pre></div>


<div class="javascript-example">
    <pre><code class="language-javascript">const url = new URL(
    "http://localhost/api/v1/payments"
);

const headers = {
    "Authorization": "Bearer {YOUR_AUTH_KEY}",
    "Content-Type": "application/json",
    "Accept": "application/json",
};

let body = {
    "user_id": 1,
    "payment_date": "2026-05-10T23:48:01",
    "amount": 1500.75,
    "cash_amount": 6,
    "credit_amount": 11,
    "method": "placeat",
    "notes": "دفعة مقدمة من الحساب",
    "is_split": true,
    "payment_method_id": 1,
    "cash_box_id": 1,
    "use_credit": false,
    "paid_at": "2023-05-20 14:30:00"
};

fetch(url, {
    method: "POST",
    headers,
    body: JSON.stringify(body),
}).then(response =&gt; response.json());</code></pre></div>

