<span id="example-requests-GETapi-v1-activity-logs">
<blockquote>Example request:</blockquote>


<div class="bash-example">
    <pre><code class="language-bash">curl --request GET \
    --get "http://localhost/api/v1/activity-logs?user_id=18&amp;subject_type=nostrum&amp;action=quod&amp;date_from=id" \
    --header "Authorization: Bearer {YOUR_AUTH_KEY}" \
    --header "Content-Type: application/json" \
    --header "Accept: application/json" \
    --data "{
    \"subject_type\": \"aspernatur\",
    \"subject_id\": 1,
    \"action\": \"rerum\",
    \"date_from\": \"2026-05-10T23:47:58\",
    \"date_to\": \"2096-03-10\",
    \"per_page\": 2,
    \"search\": \"doloribus\"
}"
</code></pre></div>


<div class="javascript-example">
    <pre><code class="language-javascript">const url = new URL(
    "http://localhost/api/v1/activity-logs"
);

const params = {
    "user_id": "18",
    "subject_type": "nostrum",
    "action": "quod",
    "date_from": "id",
};
Object.keys(params)
    .forEach(key =&gt; url.searchParams.append(key, params[key]));

const headers = {
    "Authorization": "Bearer {YOUR_AUTH_KEY}",
    "Content-Type": "application/json",
    "Accept": "application/json",
};

let body = {
    "subject_type": "aspernatur",
    "subject_id": 1,
    "action": "rerum",
    "date_from": "2026-05-10T23:47:58",
    "date_to": "2096-03-10",
    "per_page": 2,
    "search": "doloribus"
};

fetch(url, {
    method: "GET",
    headers,
    body: JSON.stringify(body),
}).then(response =&gt; response.json());</code></pre></div>

