    "description": "Dolor quidem ipsum amet nulla numquam.",
    "code": "SALE_TAX",
    "context": "sale"
};

fetch(url, {
    method: "POST",
    headers,
    body: JSON.stringify(body),
}).then(response =&gt; response.json());</code></pre></div>

